// Script Continued Below
var uiConditionCheck_ARM = Class.create();
uiConditionCheck_ARM.prototype = {
    initialize: function() {

    },

    // v2.6
    canAccept_ARM: function(gr) {
		// current.canRead() && (current.sys_id != -1 && (current.status == "submitted" || current.status == "promoted") && current.assignee == gs.getUserID())

        var answer = false;
        var isActive = gr.active;
		var canRead = gr.canRead();
		var isNewRecord = gr.isNewRecord();
        var currentUser = gs.getUserID();
		var currentUserIsAssignedMember = (gr.assignee == currentUser);

		var isSubmitted = gr.status == "submitted";
		var isPromoted = gr.status == "promoted";

        var inStatusAllowedCurrentUser = currentUserIsAssignedMember && (isSubmitted || isPromoted);
        // NOTE: this is ARM, there was no condition in this to define what user should be able to do this
        // TODO: before officially shipping ARM modules, this should be updated to limit to user who can accept a reverse approval

        if (canRead && isActive && !isNewRecord && inStatusAllowedCurrentUser) {
            answer = true;
        } else {
            answer = false;
        }
        return answer;
    },

    // v2.6
    canAcceptReverseApproval: function(gr) {
        var answer = false;
        var isActive = gr.active;
        var currentUser = gs.getUserID();
        var canRead = gr.canRead();
        // Work in Progress {13}
        var inWorkInProgress = (gr.state == 13);

		// STRY0127550 sending value instead of a display string
        var isActionAllowedForTaskType = new TaskerTypeActions().IsActionAllowed(gr.getValue("tasker_type.u_value"), 'Accept');
        var inStateAllowedCurrentUser = (isActionAllowedForTaskType && inWorkInProgress);
        // NOTE: this is ARM, there was no condition in this to define what user should be able to do this
        // TODO: before officially shipping ARM modules, this should be updated to limit to user who can accept a reverse approval

        if (canRead && isActive && inStateAllowedCurrentUser) {
            answer = true;
        } else {
            answer = false;
        }
        return answer;
    },

    // v2.6
    canComplete_ARM: function(gr) {
		// current.canRead() && (current.sys_id != -1 &&  (current.status == "accepted"  || current.status == "promoted") && current.assignee == gs.getUserID()) 

        var answer = false;
        var isActive = gr.active;
		var canRead = gr.canRead();
		var isNewRecord = gr.isNewRecord();
        var currentUser = gs.getUserID();
		var currentUserIsAssignedMember = (gr.assignee == currentUser);

		var isAccepted = gr.status == "accepted";
		var isPromoted = gr.status == "promoted";

        var inStatusAllowedCurrentUser = currentUserIsAssignedMember && (isAccepted || isPromoted);

        if (canRead && isActive && !isNewRecord && inStatusAllowedCurrentUser) {
            answer = true;
        } else {
            answer = false;
        }
        return answer;
    },

    // v2.6
    canPromoteTask_ARM: function(gr) {

        var answer = false;
        var isActive = gr.active;
		var canRead = gr.canRead();
		var inReview = (gr.state == 14);

		// STRY0127550 sending value instead of a display string
        var inActionAllowedForTaskType = new TaskerTypeActions().IsActionAllowed(gr.getValue("tasker_type.u_value"), 'Promote');
        // NOTE: this is ARM, there was no condition in this to define what user should be able to do this
        // TODO: before officially shipping ARM modules, this should be updated to limit to user who can accept a reverse approval

        if (canRead && isActive && inReview && inActionAllowedForTaskType) {
            answer = true;
        } else {
            answer = false;
        }
        return answer;
    },

    // v2.6
    canPromote_ARM: function(gr) {
		// current.canRead()  && (current.assignee_ou.parent != "") && (current.sys_id != -1 && (current.status == "accepted"  || current.status == "submitted" || current.status == "promoted") && current.assignee == gs.getUserID()) 

        var answer = false;
        var isActive = gr.active;
		var canRead = gr.canRead();
		var isNewRecord = gr.isNewRecord();
        var currentUser = gs.getUserID();
		var currentUserIsAssignedMember = (gr.assignee == currentUser);

		var isAccepted = gr.status == "accepted";
		var isSubmitted = gr.status == "submitted";
		var isPromoted = gr.status == "promoted";


		var activityOUHasParentOU = gr.assignee_ou.parent != "";

		var inStatusAllowedCurrentUser = currentUserIsAssignedMember && (isAccepted || isPromoted || isSubmitted);

		if (canRead && isActive && !isNewRecord && activityOUHasParentOU && inStatusAllowedCurrentUser) {
            answer = true;
        } else {
            answer = false;
        }
        return answer;
    },

    // v2.6
    canReturn_ARM: function(gr) {
		// current.canRead()  && (current.sys_id != -1 && (current.status == "accepted"  || current.status == "submitted" || current.status == "promoted") && current.assignee == gs.getUserID()) 

        var answer = false;
        var isActive = gr.active;
		var canRead = gr.canRead();
		var isNewRecord = gr.isNewRecord();
        var currentUser = gs.getUserID();
		var currentUserIsAssignedMember = (gr.assignee == currentUser);

		var isAccepted = gr.status == "accepted";
		var isSubmitted = gr.status == "submitted";
		var isPromoted = gr.status == "promoted";

		var inStatusAllowedCurrentUser = currentUserIsAssignedMember && (isAccepted || isPromoted || isSubmitted);

		if (canRead && isActive && !isNewRecord && inStatusAllowedCurrentUser) {
            answer = true;
        } else {
            answer = false;
        }
        return answer;
    },

    // v2.6
    canSubmit_ARM: function(gr) {
		// current.canRead() && (current.sys_id != -1 && (current.status == "draft"  || current.status == "returned") && current.assignee == gs.getUserID())

        var answer = false;
        var isActive = gr.active;
		var canRead = gr.canRead();
		var isNewRecord = gr.isNewRecord();
        var currentUser = gs.getUserID();
		var currentUserIsAssignedMember = (gr.assignee == currentUser);


		var isDraft = gr.status == "draft";
		var isReturned = gr.status == "returned";

		var inStatusAllowedCurrentUser = currentUserIsAssignedMember && (isDraft || isReturned);

		if (canRead && isActive && !isNewRecord && inStatusAllowedCurrentUser) {
            answer = true;
        } else {
            answer = false;
        }
        return answer;
    },

	type: 'uiConditionCheck_ARM'
};
